import React, { useEffect, useRef, useState } from "react";
import { useParams } from "react-router-dom";
import axios from "axios";
import { ChevronLeft, ChevronRight } from "lucide-react";

const CategoryGalleryPage = () => {
  const { section, category } = useParams();
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);
  const scrollRef = useRef(null);

  useEffect(() => {
    const fetchImages = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/gallery`);
        const filtered = res.data.filter(
          (img) =>
            img.Category?.name.toLowerCase() === category &&
            img.Category?.section.toLowerCase() === section
        );
        setImages(filtered);
      } catch (error) {
        console.error("Failed to fetch images", error);
      } finally {
        setLoading(false);
      }
    };

    fetchImages();
  }, [section, category]);

  useEffect(() => {
    const interval = setInterval(() => {
      if (scrollRef.current) {
        scrollRef.current.scrollLeft += 1;
      }
    }, 10); // Adjust the speed by changing the interval time

    return () => clearInterval(interval);
  }, []);

  const scroll = (offset) => {
    scrollRef.current.scrollLeft += offset;
  };

  return (
    <div className="bg-white min-h-screen px-6 py-10">
      <div className="max-w-full mx-auto">
        <h1 className="text-4xl font-bold text-center capitalize text-gray-900 mb-1">
          {category.replace("-", " ")}
        </h1>
        <p className="text-center text-gray-500 uppercase text-xs tracking-widest mb-8">
          Section: {section.replace("-", " ")}
        </p>

        {loading ? (
          <p className="text-center text-gray-500">Loading...</p>
        ) : images.length === 0 ? (
          <p className="text-center text-gray-400">No images found in this category.</p>
        ) : (
          <div className="relative">
            {/* Arrows */}
            <button
              onClick={() => scroll(-400)}
              className="absolute left-0 top-1/2 transform -translate-y-1/2 bg-black/60 hover:bg-black text-white p-2 z-10 rounded-full"
            >
              <ChevronLeft size={24} />
            </button>
            <button
              onClick={() => scroll(400)}
              className="absolute right-0 top-1/2 transform -translate-y-1/2 bg-black/60 hover:bg-black text-white p-2 z-10 rounded-full"
            >
              <ChevronRight size={24} />
            </button>

            {/* Horizontal Scrollable Images */}
            <div
              ref={scrollRef}
              className="flex overflow-x-hidden scrollbar-hide scroll-smooth w-full"
            >
              {images.map((img) => (
                <div
                  key={img.id}
                  className="flex-shrink-0 w-full overflow-hidden shadow-md hover:shadow-lg transition"
                >
                  <img
                    src={`http://localhost:5000${img.imageUrl}`}
                    alt={img.title}
                    className="w-full h-auto object-cover"
                  />
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CategoryGalleryPage;
